    table { width: 100%; border-collapse: collapse; margin-bottom: 20px; font-size: 14px; }
    th, td { border: 1px solid #ddd; padding: 8px; text-align: center; }
    th { background-color: #f2f2f2; color: #333; }
    tfoot td { font-weight: bold; background-color: #fafafa; }
    .footer { font-size: 12px; color: #777; text-align: center; margin-top: 20px; }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <div class="company-name">APG Consulting</div>
      <h1>Informe Consolidado Valores Mensuales</h1>
    </div>
    <table>
      <thead>
        <tr>
          <th>DB</th>
          <th>País</th>
          <th>Entorno</th>
          <th>Año</th>
          <th>Mes</th>
          <th>Mes Texto</th>
          <th>Procesados</th>
          <th>Aprobados</th>
          <th>Erróneos</th>
          <th>% Error</th>
        </tr>
      </thead>
      <tbody>
        ${filas}
      </tbody>
      <tfoot>
        <tr>
          <td colspan="6">TOTAL CONSOLIDADO</td>
          <td>${totalProcesados}</td>
          <td>${totalAprobados}</td>
          <td>${totalErroneos}</td>
          <td>${porcentajeErrorGlobal}</td>
        </tr>
      </tfoot>
    </table>
    <div class="footer">
      © ${new Date().getFullYear()} APG Consulting · Este informe fue generado automáticamente.
    </div>
  </div>
</body>
</html>
`;

return [{
  json: {
    mailSubject,
    mailBody
  }
}];

const response = $input.first().json;
const runData = response.data.resultData.runData;
const lastNode = response.data.resultData.lastNodeExecuted;

// 1. Buscamos el error técnico
const technicalError = response.data.resultData.error || {};

// 2. Buscamos el CONTEXTO REAL (País y Entorno del Credentials Loop)
let realContext = { pais: "N/A", entorno: "N/A" };

try {
  // Accedemos al historial del nodo que itera las credenciales
  const credsLoopExecs = runData["Credentials Loop"];
  // Tomamos la última vez que pasó por ese nodo
  const lastCredsExecution = credsLoopExecs[credsLoopExecs.length - 1];

  // En un 'Split in Batches', el puerto 1 (índice 1) es el que saca el ítem actual
  const currentCredsItem = lastCredsExecution.data.main[1][0].json;

  realContext.pais = currentCredsItem.country || "N/A";
  realContext.entorno = currentCredsItem.entorno || "N/A";
} catch (e) {
  realContext = { pais: "Error rastreo", entorno: "Error rastreo" };
}

// 3. Buscamos los datos de la QUERY que falló
let lastInputData = {};
try {
  const nodeExecutions = runData[lastNode];
  const lastExecution = nodeExecutions[nodeExecutions.length - 1];

  if (lastExecution.source && lastExecution.source.length > 0) {
    const sourceNodeName = lastExecution.source[0].previousNode;
    const sourceNodeExecs = runData[sourceNodeName];
    const lastSourceExec = sourceNodeExecs[sourceNodeExecs.length - 1];

    // El 'Query Loop' entrega los datos por el puerto 1
    lastInputData = lastSourceExec.data.main[1][0].json;
  }
} catch (e) {
  lastInputData = { info: "No se pudo rastrear la query" };
}

return {
  json: {
    alerta: {
      error: technicalError.message,
      stack: technicalError.stack,
      nodo_fallido: lastNode,
    },
    contexto_negocio: {
      queryId: lastInputData.queryId || "N/A",
      // AHORA SI: Usamos los datos del contexto real de conexión
      queryType: lastInputData.type,
      pais: realContext.pais,
      entorno: realContext.entorno,
    },
    meta: {
      executionId: response.id,
      timestamp: response.stoppedAt
    }
  }
};

