const now = new Date();

const getNextMonthName = () => new Date(new Date().setMonth(new Date().getMonth() + 1)).toLocaleString('es-ES', { month: 'long' }).replace(/^\w/, c => c.toUpperCase());
// targetMonth es el índice (0-11) del próximo mes.
let targetMonth = now.getMonth() + 1; 
if (targetMonth > 11) {
    targetMonth = 0; // Si es Diciembre (11), el próximo es Enero (0)
}
const targetMonthName = getNextMonthName();
const results = [];

// Función para calcular la diferencia en años (edad o antigüedad)
const calculateDifferenceInYears = (eventDate) => {
    if (!eventDate || isNaN(eventDate.getTime())) return 0;

    // Obtenemos el año en que el evento ocurrirá (actual o próximo año)
    const nextEventYear = now.getFullYear() + (targetMonth > now.getMonth() ? 0 : 1);

    // Calculamos la diferencia simple de años
    let diffYears = nextEventYear - eventDate.getFullYear();

    // Nota: Esta lógica asume que si el mes de la fecha registrada (eventDate)
    // coincide con el targetMonth, la edad calculada por la diferencia de años será la correcta
    // que tendrá en ese momento, ya que la ejecución está programada antes del evento.
    // Esto funciona bien para la antigüedad o la edad en el momento del próximo cumpleaños.

    return diffYears;
};

// 2. Iterar sobre todos los empleados traidos del nodo anterior
for (const item of $input.all()) {
    const row = item.json;

    const nameField = 'Nombre'; 
    const birthdayDateField = 'BirthdayDate'; 
    const admissionDateField = 'AdmissionDate';
    const countryField = 'Country'; // Asumiendo que el campo es 'Country'

    const chequearFecha = (fechaString, tipoEvento) => {
        if (!fechaString) return;

        const fecha = new Date(fechaString);

        // Verificar si la fecha es válida
        if (isNaN(fecha.getTime())) return;

        // Usamos getUTCMonth para evitar problemas de zona horaria con fechas ISO
        // Comparamos el mes de la fecha guardada con el mes objetivo
        // Nota: targetMonth es el índice JS (0-11) del próximo mes.
        if (fecha.getUTCMonth() === targetMonth) {

            // 1. Calcular la diferencia en años (edad o antigüedad)
            const diffAños = calculateDifferenceInYears(fecha);
            const subject = 'años';

            // 2. Formato de fecha DD/MM/YYYY
            const datePart = fecha.getUTCDate().toString().padStart(2, '0');
            const monthPart = (fecha.getUTCMonth() + 1).toString().padStart(2, '0'); // +1 para mes 1-12
            const yearPart = fecha.getUTCFullYear();
            const fechaDisplay = `${datePart}/${monthPart}/${yearPart}`;

            // 3. Icono
            const icono = tipoEvento === 'Cumpleaños' ? '🎂' : '🥇';

            // 4. Mensaje Completo (Formato deseado: 02/01/1990 | 36 años Nataly Suarez Colombia 🎂 Cumpleaños)
            const mensajeCompleto = `${fechaDisplay} | ${diffAños} ${subject}`;


            results.push({
                json: {
                    month: targetMonthName,
                    nombre: row[nameField],
                    country: row[countryField] || '',
                    tipo: tipoEvento,
                    fecha_display: fechaDisplay, // Nuevo: DD/MM/YYYY (para uso futuro)
                    fecha_sort_key: fecha.getUTCDate().toString().padStart(2, '0'), // Día (DD) para ordenar en el siguiente nodo
                    edad_o_antiguedad: diffAños,
                    mensaje_completo: mensajeCompleto // La cadena formateada final
                }
            });
        }
    };

    // Chequear Cumpleaños
    chequearFecha(row[birthdayDateField], 'Cumpleaños');

    // Chequear Aniversario
    chequearFecha(row[admissionDateField], 'Aniversario');
}

if (results.length === 0) {
    return [
        {
            json: {
                mensaje: "No se encontraron cumpleaños ni aniversarios para el próximo mes.",
                hay_eventos: false, // Bandera para identificar que NO hay datos
                mes_analizado: targetMonthName
            }
        }
    ];
}

return results;

// Obtenemos todos los items de entrada
const items = $input.all();

// 1. Verificamos si es el mensaje de "No hay eventos"
if (items.length > 0 && items[0].json.hay_eventos === false) {
	const mensajeVacio = `
		<div style="font-family: Arial, sans-serif; color: #555; padding: 20px; text-align: center; border: 1px solid #ddd; border-radius: 8px;">
			<h3>📅 Próximo Mes</h3>
			<p>No hay cumpleaños ni aniversarios registrados para el mes entrante.</p>
		</div>
	`;
	return [{ json: { html_email: mensajeVacio } }];
}

// 2. Si hay datos, los ordenamos por día (para que el email se vea ordenado cronológicamente)
// Extraemos el día de la fecha "2000-12-13" -> 13
items.sort((a, b) => {
	const diaA = parseInt(a.json.fecha_display.split('/')[2]);
	const diaB = parseInt(b.json.fecha_display.split('/')[2]);
	return diaA - diaB;
});

// 3. Construimos las filas de la tabla HTML
let filasHtml = '';

for (const item of items) {
	const empleado = item.json;
	// const dia = empleado.fecha.split('-')[2]; // Ya no se usa solo el día

	// Definimos estilos/iconos según el tipo
	let estiloBadge = '';
	let icono = '';

	if (empleado.tipo === 'Cumpleaños') {
		estiloBadge = 'background-color: #e3f2fd; color: #1565c0; border: 1px solid #bbdefb;'; // Azulito
		icono = '🎂';
	} else {
		estiloBadge = 'background-color: #fff3e0; color: #e65100; border: 1px solid #ffe0b2;'; // Naranja
		icono = '🥇';
	}

	filasHtml += `
		<tr style="border-bottom: 1px solid #eee;">
