// 1. Lista de países
const countriesList = ["Argentina", "Colombia", "Perú", "Costa Rica", "Bolivia", "Ecuador", "España"];

// Función para quitar acentos y dejar en minúsculas (Normalización)
const normalize = (text) => {
  return text.normalize("NFD")
             .replace(/[\u0300-\u036f]/g, "")
             .toLowerCase()
             .trim();
};

// 2. Obtener el contenido y limpiar HTML de Teams
let rawContent = items[0].json.body.content.replace(/<[^>]*>/g, "");

// 3. Separar por comas
let parts = rawContent.split(',').map(p => p.trim()).filter(p => p !== "");

let country = "";
let dates = [];
let nameParts = [];

// 4. Procesamiento
for (let part of parts) {
    let normalizedPart = normalize(part);

    // ¿Es un país? Comparamos versiones normalizadas
    let foundCountry = countriesList.find(c => normalize(c) === normalizedPart);

    if (foundCountry) {
        country = foundCountry; // Guardamos el nombre "bonito" (Perú)
        continue;
    }

    // ¿Es una fecha? (dd/mm/yyyy)
    if (/^\d{1,2}\/\d{1,2}\/\d{4}$/.test(part)) {
        let [day, month, year] = part.split('/');
        dates.push({
            original: part,
            dateObj: new Date(year, month - 1, day)
        });
        continue;
    }

    // Si no es país ni fecha, es el nombre
    nameParts.push(part);
}

// 5. Lógica de fechas
let birthdayDate = "";
let admissionDate = "";

if (dates.length >= 2) {
    dates.sort((a, b) => a.dateObj - b.dateObj);
    birthdayDate = dates[0].original;
    admissionDate = dates[1].original;
} else if (dates.length === 1) {
    admissionDate = dates[0].original;
}

return {
    name: nameParts.join(" "),
    country: country,
    birthdayDate: birthdayDate,
    admissionDate: admissionDate
};

