    if (String(item.pattern || "0").trim() === '2') {
        const combinedQueryText = `-- SELECT\n${item.revisionQuery || ""}\n\n-- UPDATE\n${item.correctionQuery || ""}`;
        itemHtml += `<p><b>Cargar ticket con:</b></p><pre style="${styles.pre}">${combinedQueryText}</pre>`;
