const sqlResults = items.map(i => i.json);

const contextItem = $node["Query Loop"].json;

const outputItem = JSON.parse(JSON.stringify(contextItem));
outputItem.result = sqlResults;

return { json: outputItem };

// [NODO: FAN OUT - DIVISOR]
// MODO: Run Once for ALL Items

const allOutputItems = [];
const separatorRegex = /\s*-{2,3}\s*[\r\n]+/; 

for (const item of items) {
  const parentItem = item;
  const json = parentItem.json;

  const revQuery = '@' ;
  const corQuery = json.correctionQuery || '';
  const queryId = json.queryId;

  const revQueriesParts = revQuery.split(separatorRegex).filter(p => p.trim().length > 0);

  if (revQueriesParts.length > 1) {
    // --- CASO 1: Query Particionada (1.3) ---
    const corQueriesParts = corQuery ? corQuery.split(separatorRegex).filter(p => p.trim().length > 0) : [];

    revQueriesParts.forEach((subRevQuery, index) => {
      const newItem = JSON.parse(JSON.stringify(json));
      newItem.revisionQuery = subRevQuery.trim();

      let associatedCor = null;
      if (corQueriesParts.length > 0 && corQueriesParts[index]) {
        associatedCor = corQueriesParts[index].trim();
      }
      newItem.associatedCorrection = associatedCor;

      newItem.queryType = 'revision';
      newItem.subQueryIndex = index;
      newItem.parentGroupId = queryId; 

      delete newItem.correctionQuery; // Aquí SÍ borramos porque está partida
      allOutputItems.push({ json: newItem, pairedItem: item.pairedItem });
    });

  } else {
    // --- CASO 2: Query Normal (1.2, etc) ---
    const newItem = JSON.parse(JSON.stringify(json));

    newItem.revisionQuery = revQuery.trim();
    // CORRECCIÓN AQUÍ: Mantenemos correctionQuery original para que llegue al HTML
    newItem.correctionQuery = corQuery.trim(); 

    // Opcional: dejamos associatedCorrection por si alguna lógica futura lo usa
    newItem.associatedCorrection = corQuery.trim();

    newItem.queryType = 'revision';
    newItem.subQueryIndex = 0;

    delete newItem.parentGroupId; 
    // ELIMINADO: delete newItem.correctionQuery;  <-- ESTA LÍNEA CAUSABA EL ERROR

    allOutputItems.push({ json: newItem, pairedItem: item.pairedItem });
  }
}

return allOutputItems;

// [NODO: Set HTML - Versión Final Sobria]
// MODO: Run Once for All Items

const allItems = $input.all();

// --- 0. VALIDACIÓN INICIAL ---
// Si no llegó nada al nodo, salimos.
if (allItems.length === 0) {
  // Anti-spam para ejecuciones automáticas (Bi-hourly/Nightly)
  // Nota: Aunque ya no lo mostramos en el título, seguimos usándolo para esta lógica interna.
  const type = $("Credentials Loop").first().json["type"] || "";
  if (['Bi-hourly', 'Nightly'].includes(type)) {
      return []; 
  }
  return { json: { htmlContent: "<p>No hay datos que procesar.</p>" } };
}

const allQueries = allItems.map(item => item.json);
let validHtmlParts = []; 

// Contador de puntos ocultos
let hiddenQueriesCount = 0;

// --- 1. ESTILOS (CSS Black & White) ---
const styles = {
  // Contenedores y Tablas
  table: 'border-collapse: collapse; margin-bottom: 15px; width: 100%; border: 1px solid #000;', 
  th: 'padding: 8px; text-align: left; font-weight: bold; border: 1px solid #000; background-color: #f2f2f2; color: #000; font-size: 13px;', 
  td: 'padding: 8px; vertical-align: top; border: 1px solid #000; font-size: 13px; color: #000;',

  // Tipografía y Jerarquía
  dateHeader: 'font-size: 26px; color: #000000; margin: 0 0 5px 0; font-weight: 800; letter-spacing: -0.5px;', 
  mainTitle: 'font-size: 14px; font-weight: normal; color: #000000; margin: 0 0 20px 0; text-transform: uppercase; letter-spacing: 1px;', 
  h3: 'margin-bottom: 8px; font-size: 16px; font-weight: bold; color: #000000; border-left: 4px solid #000000; padding-left: 8px;', 

  // Script y Notas
  // Nota: Quitamos el text-transform uppercase para que la oración larga se lea bien
  queryLabel: 'font-size: 14px; font-weight: bold; margin-bottom: 5px; margin-top: 15px; color: #000000;', 
  pre: 'font-family: Consolas, monospace; white-space: pre-wrap; word-wrap: break-word; font-size: 12px; margin-top: 0; background: #fafafa; padding: 10px; border: 1px solid #ccc; border-radius: 4px; color: #000;',
  p_notice: 'font-size: 12px; font-style: italic; color: #000;',

  // Separadores y Footer
  hr: 'border: 0; border-top: 1px solid #000; margin: 25px 0;',
  footerMsg: 'padding: 10px 0; color: #000; font-size: 13px; margin-top: 20px;' 
};

// --- 2. PROCESAMIENTO DE ITEMS ---
for (const item of allQueries) {
  const results = item.result;

  // A. Lógica de Vacío
  let isEmpty = false;
  if (!results) isEmpty = true;
  else if (Array.isArray(results) && results.length === 0) isEmpty = true;
  else if (Array.isArray(results) && results.length === 1) {
    const firstItem = results[0];
    if (firstItem === null || (typeof firstItem === 'object' && Object.keys(firstItem).length === 0)) {
      isEmpty = true;
    }
  }

  if (isEmpty) {
    hiddenQueriesCount++; 
    continue; 
  }

  // B. Construcción del HTML del Item
  let itemHtml = "";
  itemHtml += `<h3 style="${styles.h3}">Punto ${item.queryId}: ${item.description || "Sin descripción"}</h3>`;

  // Tabla
  let data = results;
  const MAX_ROWS = 20;
  const MAX_COLS = 8;
  let limitedRows = results.length > MAX_ROWS;
  let limitedCols = false;

  if (limitedRows) data = results.slice(0, MAX_ROWS);

  let headers = Object.keys(data[0] || {});
  if (headers.length > MAX_COLS) {
    headers = headers.slice(0, MAX_COLS);
    limitedCols = true;
  }

  itemHtml += `<table border="1" style="${styles.table}"><thead><tr>`;
  for (const header of headers) itemHtml += `<th style="${styles.th}">${header}</th>`;
  itemHtml += "</tr></thead><tbody>";

  for (const row of data) {
    itemHtml += "<tr>";
    for (const header of headers) {
      const val = row[header];
      const value = (val === null || val === undefined) ? "" : String(val).replace(/</g, '&lt;').replace(/>/g, '&gt;');
      itemHtml += `<td style="${styles.td}">${value}</td>`;
    }
    itemHtml += "</tr>";
  }
  itemHtml += "</tbody></table>";

  if (limitedRows || limitedCols) {
    itemHtml += `<p style="${styles.p_notice}">(Vista previa limitada: ${limitedRows ? MAX_ROWS + ' filas ' : ''} ${limitedCols ? MAX_COLS + ' columnas' : ''})</p>`;
  }

  // C. Script (Patrón 2)
  const pattern = String(item.pattern || "0").trim();
  if (pattern === '2') {
    const selectQuery = item.revisionQuery || "-- No select --";
    const correctionQuery = item.correctionQuery || "-- No update --";
    const combinedQueryText = `-- SELECT \n${selectQuery}\n\n-- UPDATE\n${correctionQuery}`;

    itemHtml += `<div>`;
    // NUEVO TEXTO SOLICITADO
    itemHtml += `<p style="${styles.queryLabel}">Se detectaron valores para modificar, deberá cargar un ticket con el siguiente texto:</p>`;
    itemHtml += `<pre style="${styles.pre}">${combinedQueryText}</pre>`;
    itemHtml += `</div>`;
  }

  validHtmlParts.push(itemHtml);
}

// --- 3. GENERACIÓN DEL REPORTE FINAL ---
let combinedHtml = "";

// A. Encabezado de FECHA
const now = new Date();
const options = { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' };
const dateStr = now.toLocaleDateString('es-ES', options);
const dateFormatted = dateStr.charAt(0).toUpperCase() + dateStr.slice(1);

combinedHtml += `<h1 style="${styles.dateHeader}">${dateFormatted}</h1>`;

// B. Subtítulo (Generico)
combinedHtml += `<h2 style="${styles.mainTitle}">Resultados de la revisión de Entornos</h2>`;

// C. Cuerpo del mensaje
if (validHtmlParts.length === 0) {
  // Lógica Anti-Spam para reportes automáticos vacíos
  let reportType = "General";
  try { reportType = $("Credentials Loop").first().json["type"] || "General"; } catch(e){}

  if (['Bi-hourly', 'Nightly'].includes(reportType)) return []; 

  // Mensaje "Sin novedades" limpio
  combinedHtml += `<div style="${styles.footerMsg}">✅ No se encontraron novedades ni datos para revisar en este entorno el día de hoy.</div>`;

} else {
  // Caso: Hay errores
  combinedHtml += validHtmlParts.join(`<hr style="${styles.hr}">`);

  // D. FOOTER CON MENSAJE SOLICITADO
  if (hiddenQueriesCount > 0) {
      combinedHtml += `<div style="${styles.footerMsg}">`;
      combinedHtml += `El resto de los puntos que no se muestran fueron ejecutados y no dieron resultados`;
      combinedHtml += `</div>`;
  }
}

// Retorno
const parentPairedItem = items.length > 0 ? items[0].pairedItem : undefined;
return { 
    json: { htmlContent: combinedHtml },
    pairedItem: parentPairedItem
};

