// MODO: Run Once for All Items

const groupedItems = new Map();
const finalOutput = [];

const hasData = (sqlResultData) => {
  if (!sqlResultData || !Array.isArray(sqlResultData) || sqlResultData.length === 0) return false;
  return sqlResultData.some(row => (row && Object.keys(row).length > 0));
};

for (const item of items) {
  const json = item.json;
  const parentId = json.parentGroupId;

  // --- CASO 1: ITEM NORMAL ---
  if (!parentId) {
    finalOutput.push(item);
    continue;
  }

  // --- CASO 2: ITEM PARTICIONADO ---
  if (hasData(json.result)) {
    if (!groupedItems.has(parentId)) {
      const baseItem = JSON.parse(JSON.stringify(item));
      if (baseItem.json.associatedCorrection) {
         baseItem.json.correctionQuery = baseItem.json.associatedCorrection;
      }
      baseItem.json.revisionQuery = (baseItem.json.revisionQuery || '').trim();
      baseItem.json.correctionQuery = (baseItem.json.correctionQuery || '').trim();
      groupedItems.set(parentId, baseItem);
    } else {
      const groupItem = groupedItems.get(parentId);
      const currentJson = json;
      groupItem.json.result.push(...currentJson.result);

      if (currentJson.revisionQuery) {
        groupItem.json.revisionQuery += '\n\n' + currentJson.revisionQuery.trim();
      }
      const currentCorrection = currentJson.associatedCorrection || currentJson.correctionQuery;
      if (currentCorrection) {
        const prevCorrection = groupItem.json.correctionQuery;
        groupItem.json.correctionQuery = prevCorrection 
          ? prevCorrection + '\n\n' + currentCorrection.trim() 
          : currentCorrection.trim();
      }
    }
  }
}

// Volcamos los grupos al array final
for (const groupItem of groupedItems.values()) {
  const json = groupItem.json;
  delete json.parentGroupId;
  delete json.subQueryIndex;
  delete json.queryType;
  delete json.associatedCorrection;
  groupItem.json = json;
  finalOutput.push(groupItem);
}

// CORRECCIÓN DE ORDEN: Ordenamos por queryId (ej: 1.2, 1.3, 1.4)
// Asumimos que queryId es un string como "1.2", "1.3", "4.9". 
// Usamos localeCompare con 'numeric: true' para que ordene bien números (2 vs 10).
finalOutput.sort((a, b) => {
    const idA = String(a.json.queryId || '');
    const idB = String(b.json.queryId || '');
    return idA.localeCompare(idB, undefined, { numeric: true, sensitivity: 'base' });
});

return finalOutput;

