// [NODO: FAN IN - AGREGADOR]
// MODO: Run Once for All Items

const groupedItems = new Map();
const finalOutput = [];

const hasData = (sqlResultData) => {
  if (!sqlResultData || !Array.isArray(sqlResultData) || sqlResultData.length === 0) return false;
  return sqlResultData.some(row => (row && Object.keys(row).length > 0));
};

for (const item of items) {
  const json = item.json;
  const parentId = json.parentGroupId;

  // --- CASO 1: ITEM NORMAL ---
  if (!parentId) {
    finalOutput.push(item);
    continue;
  }

  // --- CASO 2: ITEM PARTICIONADO ---
  if (hasData(json.result)) {
    if (!groupedItems.has(parentId)) {
      const baseItem = JSON.parse(JSON.stringify(item));
      if (baseItem.json.associatedCorrection) {
         baseItem.json.correctionQuery = baseItem.json.associatedCorrection;
      }
      baseItem.json.revisionQuery = (baseItem.json.revisionQuery || '').trim();
      baseItem.json.correctionQuery = (baseItem.json.correctionQuery || '').trim();
      groupedItems.set(parentId, baseItem);
    } else {
      const groupItem = groupedItems.get(parentId);
      const currentJson = json;
      groupItem.json.result.push(...currentJson.result);

      if (currentJson.revisionQuery) {
        groupItem.json.revisionQuery += '\n\n' + currentJson.revisionQuery.trim();
      }
      const currentCorrection = currentJson.associatedCorrection || currentJson.correctionQuery;
      if (currentCorrection) {
        const prevCorrection = groupItem.json.correctionQuery;
        groupItem.json.correctionQuery = prevCorrection 
          ? prevCorrection + '\n\n' + currentCorrection.trim() 
          : currentCorrection.trim();
      }
    }
  }
}

// Volcamos los grupos al array final
for (const groupItem of groupedItems.values()) {
  const json = groupItem.json;
  delete json.parentGroupId;
  delete json.subQueryIndex;
  delete json.queryType;
  delete json.associatedCorrection;
  groupItem.json = json;
  finalOutput.push(groupItem);
}

// CORRECCIÓN DE ORDEN: Ordenamos por queryId (ej: 1.2, 1.3, 1.4)
// Asumimos que queryId es un string como "1.2", "1.3", "4.9". 
// Usamos localeCompare con 'numeric: true' para que ordene bien números (2 vs 10).
finalOutput.sort((a, b) => {
    const idA = String(a.json.queryId || '');
    const idB = String(b.json.queryId || '');
    return idA.localeCompare(idB, undefined, { numeric: true, sensitivity: 'base' });
});

return finalOutput;

// Recuperamos los datos del nodo Aggregate
const tickets = items[0].json.tickets_limpios || [];

// LÓGICA DE NOMBRADO SEGURA:
// 1. Intentamos tomar el ID del primer ticket.
// 2. Si no hay tickets o falla, usamos la fecha y hora exacta (timestamp) para que sea único.
let batchId;

if (tickets.length > 0 && tickets[0].ticket_id) {
  batchId = tickets[0].ticket_id;
} else {
  // Genera un número único basado en el tiempo (ej: 1715629999)
  batchId = "backup_" + Date.now();
}

// Convertimos a JSON
const jsonString = JSON.stringify(tickets, null, 2);
const finalFileName = `tickets_lote_${batchId}.json`;

return {
  json: {
    // Estas variables van al flujo
    last_batch_id: (tickets.length > 0 && tickets[0].ticket_id) ? tickets[0].ticket_id : 0, 
    fileName: finalFileName,
    cantidad_tickets: tickets.length
  },
  binary: {
    data: {
      data: Buffer.from(jsonString).toString('base64'),
      mimeType: 'application/json',
      fileName: finalFileName
    }
  }
};

function stripHtml(html) {
  if (!html || typeof html !== 'string') return "";
  return html.replace(/<[^>]*>?/gm, '').replace(/&nbsp;/g, ' ').replace(/\s+/g, ' ').trim();
}

return items.map(item => {
  const ticket = item.json;
  const problemaInicial = stripHtml(ticket.additionalDescription || ticket.description);
  const rawComments = (ticket.ticketComments || []).sort((a, b) => new Date(a.createdAt) - new Date(b.createdAt));
  const validComments = rawComments.map(c => stripHtml(c.description)).filter(t => t.length > 2);
  const solucion = validComments.length > 0 ? validComments[validComments.length - 1] : "Sin solución";

  return {
    json: {
      ticket_id: ticket.id,
      titulo: (ticket.description || "Sin título").toString(),
      problema_inicial: problemaInicial,
      estado: ticket.ticketState?.name || "Desconocido",
      cliente: ticket.client?.name || "Interno",
      solucion_detectada: solucion,
      _batch_start_reference: item.json.batch_start_reference
    }
  };
});

// Leemos la referencia numérica que preparamos en el paso 1
const lastStartId = $("Generar Lote IDs1").first().json.id
const batchSize = 1000;

return {
  json: {
    next_start_id: lastStartId - batchSize
  }
};

// Función auxiliar para limpiar HTML y espacios
function stripHtml(html) {
  if (!html || typeof html !== 'string') return "";
  return html
    .replace(/<[^>]*>?/gm, ' ') // Reemplaza tags por espacio para evitar palabras pegadas
    .replace(/&nbsp;/g, ' ')
    .replace(/\s+/g, ' ') // Colapsa múltiples espacios en uno
    .trim();
}

return items.map(item => {
  const t = item.json;

  // 1. Obtener y limpiar descripciones base
  const asunto = stripHtml(t.description);
  // A veces additionalDescription es null, usamos description como fallback
  const problemaInicial = stripHtml(t.additionalDescription) || asunto;

  // 2. Procesar Comentarios (La parte crítica)
  let comentariosRaw = (t.ticketComments || [])
    // Ordenar por fecha (del más viejo al más nuevo)
    .sort((a, b) => new Date(a.createdAt) - new Date(b.createdAt))
    // Limpiar texto
    .map(c => stripHtml(c.description))
    // Eliminar comentarios vacíos o muy cortos (menos de 3 letras, ej: "Ok")
    .filter(text => text && text.length > 3);

  // 3. Deduplicar comentarios consecutivos idénticos
  // Esto soluciona el problema de "se repite 3 veces el mismo mensaje"
  let comentariosUnicos = comentariosRaw.filter((texto, index, arr) => {
    return index === 0 || texto !== arr[index - 1];
  });

  // 4. Limpiar redundancia del Problema vs Primer Comentario
  // Si el primer comentario es igual al problema inicial, lo quitamos de la lista
  if (comentariosUnicos.length > 0 && comentariosUnicos[0] === problemaInicial) {
    comentariosUnicos.shift(); 
  }

  // 5. Separar Solución vs Conversación
  // Asumimos que el ÚLTIMO mensaje es la solución o el cierre del ticket.
  let solucion = "No se registró una solución explícita en los comentarios.";
  let historialConversacion = [];

  if (comentariosUnicos.length > 0) {
    solucion = comentariosUnicos.pop(); // Sacamos el último elemento y lo guardamos como solución
    historialConversacion = comentariosUnicos; // El resto queda como historia
  }

  // 6. Construir Metadata (Para filtros estrictos)
  const metadata = {
    ticket_id: t.id,
    fecha_creacion: t.createdAt, // Importante para saber si es viejo o nuevo
    cliente: t.client?.name || "Desconocido",
    categoria: t.ticketClasification?.name || "General", // Usa la clasificación humana si existe
    estado: t.ticketState?.name || "Desconocido",
    url_ticket: `https://tu-sistema-tickets.com/ticket/${t.id}` // Opcional: útil para referencia
  };

  // 7. Construir el BLOQUE DE TEXTO FINAL (Content) para el Vector Store
  // Este formato ayuda al LLM a distinguir qué es qué.
  const contenidoVectorial = `
TICKET ID: ${t.id}
FECHA: ${t.createdAt}
CATEGORÍA: ${metadata.categoria}
CLIENTE: ${metadata.cliente}

ASUNTO:
${asunto}

DESCRIPCIÓN DEL PROBLEMA:
${problemaInicial}

HISTORIAL DE CONVERSACIÓN (Pasos intermedios):
${historialConversacion.length > 0 ? historialConversacion.map(c => `- ${c}`).join('\n') : "Sin intercambio intermedio."}

SOLUCIÓN TÉCNICA / RESOLUCIÓN FINAL:
${solucion}
`.trim();

  // Devolver estructura compatible con Vector Store
  return {
    json: {
      id: t.id,
      content: contenidoVectorial, // Esto es lo que se incrusta (embedding)
      metadata: metadata // Esto va a las columnas de metadatos (filtro)
    }
  };
});

// 1. Obtener el archivo binario.
// Asegúrate de que el nombre del campo en el nodo anterior coincida.
// En un Form Trigger suele llamarse 'data' o el nombre del campo del formulario (ej. 'file').
// Si tu input binario se llama diferente, cambia 'data' por ese nombre.
const binaryData = $input.item.binary.data; // <--- VERIFICA ESTE NOMBRE

if (!binaryData) {
  throw new Error("No se encontró información binaria. Verifica el nombre del campo.");
}

// 2. Convertir el binario (Base64) a texto y luego a objeto JSON
const jsonString = Buffer.from(binaryData.data, 'base64').toString('utf8');
const tickets = JSON.parse(jsonString);

// Verificamos que sea un array
if (!Array.isArray(tickets)) {
  throw new Error("El archivo JSON no contiene un array de tickets.");
}

// 3. Devolver los tickets como ítems individuales
// Esto "explota" el array: si entran 1 archivo, salen 8000 ítems
return tickets.map(ticket => {
  // Lógica de metadatos que ya tenías
  const fileName = binaryData.fileName || "unknown.json";
  const type = fileName.toLowerCase().includes("manual") ? "manual" : "ticket";

  return {
    json: {
      ...ticket, // Mantiene todas las propiedades del ticket (id, asunto, etc.)
      metadata: {
        source: fileName,
        type: type,
        ingest_date: new Date().toISOString()
      }
    }
  };
});

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.myNewField = 1;
}

return $input.all();

const sqlResults = $("SQL Execute").all().map(i => i.json);

const contextItem = $node["Query Loop"].json;

const outputItem = JSON.parse(JSON.stringify(contextItem));
outputItem.result = sqlResults;

return { json: outputItem };

// [NODO: FAN OUT - DIVISOR]
// MODO: Run Once for ALL Items

const allOutputItems = [];
const separatorRegex = /\s*-{2,3}\s*[\r\n]+/; 

for (const item of items) {
  const parentItem = item;
  const json = parentItem.json;

  const revQuery = json.revisionQuery || '';
  const corQuery = json.correctionQuery || '';
  const queryId = json.queryId;

  const revQueriesParts = revQuery.split(separatorRegex).filter(p => p.trim().length > 0);

  if (revQueriesParts.length > 1) {
    // --- CASO 1: Query Particionada (1.3) ---
    const corQueriesParts = corQuery ? corQuery.split(separatorRegex).filter(p => p.trim().length > 0) : [];

    revQueriesParts.forEach((subRevQuery, index) => {
      const newItem = JSON.parse(JSON.stringify(json));
      newItem.revisionQuery = subRevQuery.trim();

      let associatedCor = null;
      if (corQueriesParts.length > 0 && corQueriesParts[index]) {
        associatedCor = corQueriesParts[index].trim();
      }
      newItem.associatedCorrection = associatedCor;

      newItem.queryType = 'revision';
      newItem.subQueryIndex = index;
      newItem.parentGroupId = queryId; 

      delete newItem.correctionQuery; // Aquí SÍ borramos porque está partida
      allOutputItems.push({ json: newItem, pairedItem: item.pairedItem });
    });

  } else {
    // --- CASO 2: Query Normal (1.2, etc) ---
    const newItem = JSON.parse(JSON.stringify(json));

    newItem.revisionQuery = revQuery.trim();
    // CORRECCIÓN AQUÍ: Mantenemos correctionQuery original para que llegue al HTML
    newItem.correctionQuery = corQuery.trim(); 

    // Opcional: dejamos associatedCorrection por si alguna lógica futura lo usa
    newItem.associatedCorrection = corQuery.trim();

    newItem.queryType = 'revision';
    newItem.subQueryIndex = 0;

    delete newItem.parentGroupId; 
    // ELIMINADO: delete newItem.correctionQuery;  <-- ESTA LÍNEA CAUSABA EL ERROR

    allOutputItems.push({ json: newItem, pairedItem: item.pairedItem });
  }
}

return allOutputItems;

// [NODO: Set HTML - Versión Ultra-Ligera]
