const all = $input.all();
const now = new Date();
const d7  = new Date(now - 7*24*60*60*1000);
const d14 = new Date(now - 14*24*60*60*1000);

const s = rows => {
  const t = rows.length, ok = rows.filter(r=>r.json.status==='success').length;
  const er = rows.filter(r=>r.json.status==='error').length;
  return { t, ok, er, rate: t>0?((ok/t)*100).toFixed(1):'0.0' };
};

const rec  = all.filter(i=>i.json.started_at && new Date(i.json.started_at)>=d7);
const prev = all.filter(i=>{const d=new Date(i.json.started_at);return d>=d14&&d<d7;});
const r7=s(rec), p7=s(prev);
const delta=( parseFloat(r7.rate)-parseFloat(p7.rate) ).toFixed(1);

const errMap={};
rec.filter(i=>i.json.status==='error').forEach(i=>{
  const n=i.json.workflow_name||'Unknown'; errMap[n]=(errMap[n]||0)+1;
});
const worst=Object.entries(errMap).sort((a,b)=>b[1]-a[1])[0];

const sample=rec.filter(i=>i.json.status==='error'&&i.json.error_message)
  .slice(0,8).map(i=>`[${i.json.workflow_name}] ${i.json.error_node}: ${i.json.error_message}`).join('\n');

return [{ json: {
  period: d7.toISOString().split('T')[0]+' → '+now.toISOString().split('T')[0],
  total:r7.t, success:r7.ok, errors:r7.er, rate:r7.rate,
  prevRate:p7.rate, delta:(delta>0?'+':'')+delta+'%',
  mostUnstable: worst ? `${worst[0]} (${worst[1]} errores)` : 'Ninguno',
  errorSample: sample || 'Sin errores recientes'
}}];

